import React, { useState, useEffect, useCallback } from 'react';
import { ShoppingBag, Clock, MapPin, ShoppingCart, Store, Radar, BellRing, Search, Loader2, AlertTriangle } from 'lucide-react';
import { api } from '../services/api'; 
import { useCart } from '../context/CartContext'; 
import { useAuth } from '../context/AuthContext';
import { calcularDistancia } from '../utils/radarService';
import Carrito from './Carrito';
import MisPedidosCliente from './MisPedidosCliente';

const PanelCliente = () => {
    const [tab, setTab] = useState('tienda'); 
    const [ofertasPorLocal, setOfertasPorLocal] = useState({});
    const { addToCart, count, cart, total, clearCart } = useCart(); 
    const { user } = useAuth();
    
    const [busqueda, setBusqueda] = useState("");
    const [verCarrito, setVerCarrito] = useState(false);
    const [radarActivo, setRadarActivo] = useState(false);
    const [notificaciones, setNotificaciones] = useState([]);
    const [favoritos, setFavoritos] = useState([]); 
    const [loading, setLoading] = useState(true);
    const [isCheckingOut, setIsCheckingOut] = useState(false);

    const currentUserId = user?.id || user?._id;

    // 1. CARGAR DATOS (Sincronización con la nube)
    const cargarDatos = useCallback(async () => {
        setLoading(true);
        try {
            const todasLasOfertas = await api.getTodasLasOfertas();
            
            const agrupado = todasLasOfertas.reduce((acc, oferta) => {
                const local = oferta.local;
                if (!local) return acc;
                const localNombre = local.nombre || "Sin Nombre";
                
                if (!acc[localNombre]) {
                    acc[localNombre] = { 
                        info: { 
                            id: local._id, 
                            nombre: localNombre, 
                            direccion: local.direccion,
                            lng: local.location?.coordinates[0], 
                            lat: local.location?.coordinates[1] 
                        }, 
                        ofertas: [] 
                    };
                }
                acc[localNombre].ofertas.push(oferta);
                return acc;
            }, {});
            setOfertasPorLocal(agrupado);
        } catch (error) {
            console.error("Error al sincronizar con la nube:", error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        cargarDatos();
        const guardados = JSON.parse(localStorage.getItem(`favs-${currentUserId}`) || "[]");
        setFavoritos(guardados);
    }, [cargarDatos, currentUserId]);

    // LÓGICA DE CHECKOUT (ADAPTADA AL VENDEDOR)
    const handleCheckout = async () => {
        if (cart.length === 0) return;

        try {
            setIsCheckingOut(true);
            
            // Tomamos el ID del local del primer item del carrito (asumiendo compra por local)
            const localId = cart[0].local?._id || cart[0].local;

            const pedidoData = {
                cliente: currentUserId,
                local: localId, // <--- Crucial para que el Vendedor lo vea
                items: cart.map(item => ({
                    producto: item.Producto, // <--- Coincide con p.items.map(item.producto) del vendedor
                    cantidad: item.cantidad,
                    precio: item.P_Nuevo,     // <--- Coincide con la lógica de precios
                    oferta: item._id
                })),
                total: total,
                puntoEntrega: {
                    direccion: "Retiro en Local"
                },
                estado: 'proceso' // <--- Iniciamos en 'proceso' para activar botón "Despachar" en vendedor
            };

            const response = await api.crearPedido(pedidoData);

            if (response) {
                alert("¡Pedido enviado con éxito! El vendedor lo está procesando.");
                clearCart();
                setVerCarrito(false);
                setTab('pedidos');
            }
        } catch (error) {
            console.error("Error en checkout:", error);
            alert("No se pudo procesar el pedido.");
        } finally {
            setIsCheckingOut(false);
        }
    };

    // 2. LÓGICA DEL RADAR (GPS)
    useEffect(() => {
        let watchId = null;
        if (radarActivo && navigator.geolocation) {
            watchId = navigator.geolocation.watchPosition((pos) => {
                const { latitude, longitude } = pos.coords;
                const encontradas = [];
                Object.values(ofertasPorLocal).forEach(grupo => {
                    const dist = calcularDistancia(latitude, longitude, grupo.info.lat, grupo.info.lng);
                    if (dist <= 1.5) {
                        grupo.ofertas.forEach(o => {
                            const esFavorito = favoritos.some(f => o.Producto?.toLowerCase().includes(f.toLowerCase()));
                            if (esFavorito && o.Stock > 0) {
                                encontradas.push({ ...o, dist: dist.toFixed(2), localNombre: grupo.info.nombre });
                            }
                        });
                    }
                });
                setNotificaciones(encontradas);
            }, null, { enableHighAccuracy: true });
        }
        return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
    }, [radarActivo, ofertasPorLocal, favoritos]);

    if (loading || isCheckingOut) return (
        <div style={loaderStyle}>
            <Loader2 size={40} className="spinner" />
            <p>{isCheckingOut ? "Procesando pedido para el vendedor..." : "Sincronizando con la nube..."}</p>
        </div>
    );

    return (
        <div style={layout}>
            <div style={tabContainer}>
                <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? tabActive : tabBtn}>
                    <ShoppingBag size={18} /> Tienda
                </button>
                <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? tabActive : tabBtn}>
                    <ShoppingCart size={18} /> Carrito ({count})
                </button>
                <button onClick={() => {setTab('pedidos'); setVerCarrito(false)}} style={tab === 'pedidos' ? tabActive : tabBtn}>
                    <Clock size={18} /> Mis Pedidos
                </button>
            </div>

            <main style={mainContent}>
                {tab === 'tienda' && !verCarrito && (
                    <div style={{ maxWidth: '1000px', margin: '0 auto' }}>
                        <div style={radarCard(radarActivo)}>
                            <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
                                <div style={radarCircle(radarActivo)}>
                                    <Radar size={24} color={radarActivo ? "#fff" : "#e67e22"} />
                                </div>
                                <div style={{flex: 1}}>
                                    <h3 style={{margin: 0}}>Radar de Ahorro</h3>
                                    <p style={{margin: 0, fontSize: '0.85rem', opacity: 0.8}}>
                                        {radarActivo ? `Buscando tus favoritos cerca...` : 'Activa para recibir alertas al pasar por un local.'}
                                    </p>
                                </div>
                                <button onClick={() => setRadarActivo(!radarActivo)} style={btnRadar(radarActivo)}>
                                    {radarActivo ? 'APAGAR' : 'ENCENDER'}
                                </button>
                            </div>
                            {radarActivo && notificaciones.length > 0 && (
                                <div style={notifBox}>
                                    {notificaciones.map(n => (
                                        <div key={n._id} style={notifItem}>
                                            <BellRing size={18} color="#e67e22" />
                                            <div style={{flex: 1}}>
                                                <div style={{fontSize: '0.85rem', fontWeight: 'bold'}}>{n.Producto} ¡A solo {n.dist} km!</div>
                                                <div style={{fontSize: '0.75rem'}}>{n.localNombre}</div>
                                            </div>
                                            <button style={btnIr} onClick={() => addToCart(n)}>Sumar</button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        <div style={searchBox}>
                            <Search size={20} color="#94a3b8" />
                            <input 
                                style={input} 
                                placeholder="¿Buscas carne, lácteos, bebidas...?" 
                                value={busqueda} 
                                onChange={(e) => setBusqueda(e.target.value)}
                            />
                        </div>

                        {Object.keys(ofertasPorLocal).map(nombreLocal => {
                            const local = ofertasPorLocal[nombreLocal].info;
                            const ofertasFiltradas = ofertasPorLocal[nombreLocal].ofertas.filter(o => 
                                o.Producto?.toLowerCase().includes(busqueda.toLowerCase())
                            );

                            if (ofertasFiltradas.length === 0) return null;

                            return (
                                <div key={nombreLocal} style={tiendaSeccion}>
                                    <div style={headerTienda}>
                                        <div style={avatarTienda}><Store size={22} color="#e67e22" /></div>
                                        <div>
                                            <h3 style={{margin: 0}}>{nombreLocal}</h3>
                                            <span style={direccionText}><MapPin size={12} /> {local.direccion}</span>
                                        </div>
                                    </div>
                                    <div style={scrollRow}>
                                        {ofertasFiltradas.map(o => (
                                            <div key={o._id} style={cardShop}>
                                                <div style={imgContainer}>
                                                    <img src={o.imagenUrl || "https://via.placeholder.com/150"} style={imgShop} alt={o.Producto} />
                                                    {o.Stock <= 5 && o.Stock > 0 && <div style={lowStockTag}>¡Últimos {o.Stock}!</div>}
                                                </div>
                                                <div style={{padding: '15px'}}>
                                                    <h4 style={h4Item}>{o.Producto}</h4>
                                                    <div style={priceWrapper}>
                                                        <span style={pPrecio}>${o.P_Nuevo}</span>
                                                        {o.P_Viejo > o.P_Nuevo && <span style={oldPrice}>${o.P_Viejo}</span>}
                                                    </div>
                                                    <button 
                                                        style={o.Stock > 0 ? btnAdd : btnNoStock} 
                                                        onClick={() => o.Stock > 0 && addToCart(o)}
                                                        disabled={o.Stock === 0}
                                                    >
                                                        {o.Stock > 0 ? <><ShoppingCart size={16} /> Agregar</> : <><AlertTriangle size={16} /> Sin Stock</>}
                                                    </button>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}
                {verCarrito && <Carrito onCheckout={handleCheckout} />}
                {tab === 'pedidos' && <MisPedidosCliente />}
            </main>
        </div>
    );
};

// --- ESTILOS ---
const layout = { minHeight: '100vh', background: '#f8fafc' };
const tabContainer = { display: 'flex', justifyContent: 'center', gap: '10px', padding: '15px', background: 'white', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: '0', zIndex: 100 };
const tabBtn = { display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 18px', border: 'none', background: 'none', color: '#64748b', cursor: 'pointer', borderRadius: '12px', fontWeight: '600' };
const tabActive = { ...tabBtn, background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22' };
const mainContent = { padding: '20px' };
const searchBox = { display: 'flex', alignItems: 'center', background: 'white', padding: '12px 20px', borderRadius: '15px', marginBottom: '25px', border: '1px solid #e2e8f0', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' };
const input = { flex: 1, border: 'none', outline: 'none', marginLeft: '10px', fontSize: '1rem' };
const tiendaSeccion = { marginBottom: '30px', background: 'white', padding: '20px', borderRadius: '20px', border: '1px solid #f1f5f9' };
const headerTienda = { display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '20px' };
const avatarTienda = { width: '40px', height: '40px', background: '#fff7ed', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const direccionText = { fontSize: '0.8rem', color: '#94a3b8', display: 'flex', alignItems: 'center', gap: '4px' };
const scrollRow = { display: 'flex', gap: '15px', overflowX: 'auto', paddingBottom: '10px' };
const cardShop = { minWidth: '200px', background: 'white', borderRadius: '18px', border: '1px solid #f1f5f9', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const imgContainer = { position: 'relative', height: '130px', background: '#f8fafc' };
const imgShop = { width: '100%', height: '100%', objectFit: 'contain', padding: '10px' };
const lowStockTag = { position: 'absolute', bottom: '5px', left: '5px', background: '#ef4444', color: 'white', fontSize: '0.65rem', padding: '2px 8px', borderRadius: '5px', fontWeight: 'bold' };
const h4Item = { margin: '0 0 5px 0', fontSize: '0.9rem', color: '#1e293b' };
const priceWrapper = { display: 'flex', alignItems: 'baseline', gap: '8px', marginBottom: '10px' };
const pPrecio = { fontSize: '1.2rem', fontWeight: '800', color: '#1e293b' };
const oldPrice = { fontSize: '0.8rem', color: '#94a3b8', textDecoration: 'line-through' };
const btnAdd = { width: '100%', padding: '10px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', fontWeight: 'bold' };
const btnNoStock = { ...btnAdd, background: '#e2e8f0', color: '#94a3b8', cursor: 'not-allowed' };
const radarCard = (activo) => ({ background: activo ? '#1e293b' : '#fff', color: activo ? '#fff' : '#1e293b', padding: '20px', borderRadius: '20px', marginBottom: '25px', border: '1px solid #e2e8f0', transition: '0.3s' });
const radarCircle = (activo) => ({ width: '50px', height: '50px', background: activo ? '#e67e22' : '#fff7ed', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' });
const btnRadar = (activo) => ({ padding: '8px 16px', borderRadius: '10px', border: 'none', background: activo ? '#ef4444' : '#e67e22', color: 'white', cursor: 'pointer', fontWeight: 'bold' });
const notifBox = { marginTop: '15px', display: 'flex', flexDirection: 'column', gap: '10px' };
const notifItem = { background: 'rgba(255,255,255,0.05)', padding: '12px', borderRadius: '12px', display: 'flex', alignItems: 'center', gap: '12px', border: '1px solid rgba(255,255,255,0.1)' };
const btnIr = { background: '#e67e22', color: 'white', border: 'none', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontSize: '0.75rem', fontWeight: 'bold' };
const loaderStyle = { display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', height: '100vh', color: '#e67e22', gap: '10px' };

export default PanelCliente;
